import Link from 'next/link';
import { ArrowRight, MapPinned, Sparkles } from 'lucide-react';

export default function HomePage() {
  return (
    <section className="relative overflow-hidden rounded-2xl border border-white/40 bg-oasis-gradient px-6 py-14 shadow-soft sm:px-10 sm:py-20">
      <div className="pointer-events-none absolute -right-20 -top-20 h-72 w-72 rounded-full bg-terracotta/20 blur-3xl" />
      <div className="pointer-events-none absolute -bottom-24 -left-16 h-72 w-72 rounded-full bg-palmier/20 blur-3xl" />

      <div className="relative mx-auto max-w-4xl">
        <p className="mb-4 inline-flex items-center gap-2 rounded-full border border-white/50 bg-white/70 px-4 py-2 text-xs font-medium uppercase tracking-[0.2em] text-palmier shadow-lg backdrop-blur-md">
          <Sparkles size={14} />
          MVP Multi-Cooperatives
        </p>

        <h1 className="max-w-3xl text-3xl font-bold leading-tight text-palmier sm:text-5xl">
          Decouvrez les cooperatives du Draa-Tafilalet.
        </h1>

        <p className="mt-5 max-w-2xl text-base text-palmier/85 sm:text-lg">
          Produits du terroir, artisanat et savoir-faire local. Explorez la carte et soutenez
          l’economie locale.
        </p>

        <div className="mt-8 flex flex-wrap items-center gap-4">
          <Link
            href="/explore"
            className="inline-flex items-center gap-2 rounded-full bg-terracotta px-6 py-3 text-sm font-semibold text-white shadow-lg transition hover:translate-y-[-1px] hover:shadow-xl"
          >
            Explorer la carte
            <ArrowRight size={16} />
          </Link>

          <div className="inline-flex items-center gap-2 rounded-full border border-white/60 bg-white/70 px-5 py-3 text-sm text-palmier/90 shadow-lg backdrop-blur-md">
            <MapPinned size={16} />
            Navigation geolocalisee fluide
          </div>
        </div>
      </div>
    </section>
  );
}
